mapper.select:
select * from hc_barcode_master
where del_flag = 0
  and tenant_id = #{tenantId}

    and barcode_value like concat('%', #{barcodeValue}, '%')


    and value_level = #{valueLevel}


    and business_type_code = #{businessTypeCode}


    and bill_no like concat('%', #{billNo}, '%')


    and material_name like concat('%', #{materialName}, '%')

order by create_time desc

select * from hc_barcode_flow
where del_flag = 0
  and tenant_id = #{tenantId}

    and hc_barcode_master_id = #{hcBarcodeMasterId}


    and barcode_value like concat('%', #{barcodeValue}, '%')

order by event_time desc, id desc

select * from hc_barcode_master
where tenant_id = #{tenantId}
  and barcode_value = #{barcodeValue}
  and del_flag = 0
limit 1

select * from hc_barcode_master
where tenant_id = #{tenantId}
  and id = #{id}
  and del_flag = 0
limit 1

select ifnull(max(seq_no), 0) + 1 from hc_barcode_flow
where tenant_id = #{tenantId}
  and hc_barcode_master_id = #{hcBarcodeMasterId}
  and del_flag = 0
